// Formater la liste des bans
const response = $input.item.json.result || $input.item.json;
const data = response.data || response;

// Collecter tous les bans de toutes les instances
let allBans = [];
if (typeof data === 'object') {
  for (const [instance, instanceData] of Object.entries(data)) {
    // La structure réelle est instanceData.data (pas instanceData.bans)
    const bans = instanceData.data || instanceData.bans || [];
    if (Array.isArray(bans)) {
      allBans = allBans.concat(bans.map(ban => ({
        ...ban,
        instance: instance
      })));
    }
  }
}

if (allBans.length === 0) {
  return {
    json: {
      success: true,
      message: "Aucune IP bannie actuellement.",
      bans: []
    }
  };
}

let formattedText = `IPs bannies (${allBans.length}) :\n\n`;

allBans.forEach((ban, idx) => {
  formattedText += `${idx + 1}. **${ban.ip}**\n`;
  formattedText += `   • Instance: ${ban.instance}\n`;
  formattedText += `   • Raison: ${ban.reason || 'Non spécifiée'}\n`;

  if (ban.exp === 0) {
    formattedText += `   • Durée: Permanent\n`;
  } else {
    const expiresIn = Math.floor(ban.exp / 3600);
    formattedText += `   • Expire dans: ${expiresIn}h\n`;
  }

  if (ban.service) {
    formattedText += `   • Service: ${ban.service}\n`;
  } else {
    formattedText += `   • Scope: Global\n`;
  }

  if (ban.country) {
    formattedText += `   • Pays: ${ban.country}\n`;
  }

  formattedText += '\n';
});

return {
  json: {
    success: true,
    message: formattedText,
    bans: allBans,
    count: allBans.length
  }
};
